import React from "react";

import styles from "./WidgetCard.module.css";

export type WidgetSize = "xs-a" | "xs-b" | "sm-a" | "sm-b";

export interface WidgetCardProps extends React.HTMLAttributes<HTMLDivElement> {
  title?: string;
  icon?: React.ReactNode;
  children: React.ReactNode;
  size?: WidgetSize | "sm" | "md" | "lg";
  overlay?: React.ReactNode;
}

export function WidgetCard({
  title,
  icon,
  children,
  size = "sm-b",
  className = "",
  overlay,
  style,
  ...props
}: WidgetCardProps) {
  const sizeClassMap: Record<Exclude<WidgetCardProps["size"], undefined>, string> =
    {
      "xs-a": styles.widgetXsA,
      "xs-b": styles.widgetXsB,
      "sm-a": styles.widgetSmA,
      "sm-b": styles.widgetSmB,
      sm: styles.widgetSmA,
      md: styles.widgetSmB,
      lg: styles.widgetSmB,
    };
  const sizeClass = sizeClassMap[size] || styles.widgetSmB;

  return (
    <div
      className={`${sizeClass} ${className}`.trim()}
      style={{ position: "relative", ...style }}
      {...props}
    >
      {title ? (
        <div className={styles.header}>
          <div className={styles.titleRow}>
            {icon ? <div className={styles.icon}>{icon}</div> : null}
            <h3 className={styles.title}>{title}</h3>
          </div>
        </div>
      ) : null}
      <div className={styles.body}>{children}</div>
      {overlay}
    </div>
  );
}

export default WidgetCard;

.widgetXsA,
.widgetXsB,
.widgetSmA,
.widgetSmB {
  background: var(--border-color);
  border: none;
  border-radius: 2px;
  overflow: hidden;
  transition: background 200ms ease;
}

.widgetXsA:hover,
.widgetXsB:hover,
.widgetSmA:hover,
.widgetSmB:hover {
  background: var(--text-primary);
}

.widgetXsA {
  grid-column: span 1;
  grid-row: span 1;
  min-height: 180px;
}

.widgetXsB {
  grid-column: span 1;
  grid-row: span 2;
  min-height: 360px;
}

.widgetSmA {
  grid-column: span 2;
  grid-row: span 1;
  min-height: 180px;
}

.widgetSmB {
  grid-column: span 2;
  grid-row: span 2;
  min-height: 360px;
}

.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
  border-bottom: 1px solid var(--border-color);
}

.titleRow {
  display: flex;
  align-items: center;
  gap: 8px;
}

.icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.title {
  margin: 0;
  color: var(--text-primary);
  font-family: var(--font-mono);
  font-size: 14px;
  font-weight: 600;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

.body {
  padding: 12px 16px;
}
